#pragma once

#include <cuda_runtime.h>
#include <cuda_bf16.h>
#include <torch/extension.h>

// Kernel Launch Configuration
#define HIDDEN_SIZE 7168
#define THREADS_PER_BLOCK 256
#define STRIDE (HIDDEN_SIZE / THREADS_PER_BLOCK)
#define EPS 1e-6f

/**
 * Launches the RMSNorm kernel optimized for A800 (Hopper) architecture.
 * 
 * @param hidden_states Input tensor [batch_size, hidden_size] (BF16)
 * @param weight Weight tensor [hidden_size] (BF16)
 * @param output Output tensor [batch_size, hidden_size] (BF16)
 * @param batch_size Number of samples in the batch
 */
void launch_rmsnorm_kernel(
    at::Tensor hidden_states,
    at::Tensor weight,
    at::Tensor output,
    int batch_size
);

#include <cuda_runtime.h>
#include <cuda_bf16.h>
#include <cuda_fp16.h>
#include "kernel.h"

/**
 * RMSNorm Kernel optimized for A800 (Hopper) GPU.
 * 
 * Optimization Strategies:
 * 1. One block per row (batch item) to maximize shared memory usage for reduction.
 * 2. Warp-level reduction using __shfl_down_sync for efficiency.
 * 3. Block-level reduction using shared memory.
 * 4. Accumulation in float32 to match reference accuracy.
 * 5. Coalesced memory access for input, output, and weight.
 * 6. Hardcoded HIDDEN_SIZE (7168) for loop unrolling opportunities and stride calculation.
 */
__global__ void rmsnorm_kernel(
    const nv_bfloat16* __restrict__ input,
    const nv_bfloat16* __restrict__ weight,
    nv_bfloat16* __restrict__ output,
    int batch_size,
    int hidden_size,
    float eps
) {
    int row = blockIdx.x;
    int tid = threadIdx.x;

    // Shared memory for block reduction (8 warps * 1 float)
    __shared__ float warp_sums[THREADS_PER_BLOCK / 32];

    // Phase 1: Compute Sum of Squares
    float sum_sq = 0.0f;

    // Each thread processes STRIDE elements (28 elements for 7168/256)
    for (int i = tid; i < hidden_size; i += THREADS_PER_BLOCK) {
        int idx = row * hidden_size + i;
        float val = __bfloat162float(input[idx]);
        sum_sq += val * val;
    }

    // Warp-level reduction
    int lane = tid % 32;
    int warp_id = tid / 32;
    float warp_sum = sum_sq;

    // Standard warp shuffle reduction
    #pragma unroll
    for (int offset = 16; offset > 0; offset >>= 1) {
        warp_sum += __shfl_down_sync(0xffffffff, warp_sum, offset);
    }

    // Store warp sum to shared memory if warp leader
    if (lane == 0) {
        warp_sums[warp_id] = warp_sum;
    }
    __syncthreads();

    // Block-level reduction (only warp 0 proceeds)
    float block_sum = 0.0f;
    if (warp_id == 0) {
        // Load from shared memory
        float s = warp_sums[lane];
        // Reduce within warp 0
        #pragma unroll
        for (int offset = 16; offset > 0; offset >>= 1) {
            s += __shfl_down_sync(0xffffffff, s, offset);
        }
        if (lane == 0) {
            block_sum = s;
        }
    }
    __syncthreads();

    // Broadcast block_sum to all threads (stored in warp_sums[0])
    float rs = 0.0f;
    if (tid == 0) {
        rs = block_sum;
    }
    // Use shared memory to broadcast
    if (tid == 0) warp_sums[0] = rs;
    __syncthreads();
    rs = warp_sums[0];

    // Compute Inverse RMS
    float inv_rms = 1.0f / sqrtf(rs / hidden_size + eps);

    // Phase 2: Normalize and Apply Weight
    for (int i = tid; i < hidden_size; i += THREADS_PER_BLOCK) {
        int idx = row * hidden_size + i;
        float val = __bfloat162float(input[idx]);
        float w = __bfloat162float(weight[i]);

        float out_val = val * inv_rms * w;
        output[idx] = __float2bfloat16(out_val);
    }
}

void launch_rmsnorm_kernel(
    at::Tensor hidden_states,
    at::Tensor weight,
    at::Tensor output,
    int batch_size
) {
    // Get raw pointers
    const nv_bfloat16* input_ptr = reinterpret_cast<const nv_bfloat16*>(hidden_states.data_ptr<at::BFloat16>());
    const nv_bfloat16* weight_ptr = reinterpret_cast<const nv_bfloat16*>(weight.data_ptr<at::BFloat16>());
    nv_bfloat16* output_ptr = reinterpret_cast<nv_bfloat16*>(output.data_ptr<at::BFloat16>());

    // Launch Configuration
    dim3 grid(batch_size);
    dim3 block(THREADS_PER_BLOCK);

    // Launch Kernel
    rmsnorm_kernel<<<grid, block>>>(
        input_ptr,
        weight_ptr,
        output_ptr,
        batch_size,
        HIDDEN_SIZE,
        EPS
    );

    // Check for launch errors
    cudaError_t err = cudaGetLastError();
    if (err != cudaSuccess) {
        throw std::runtime_error(cudaGetErrorString(err));
    }
}

#include <torch/extension.h>
#include <cuda_runtime.h>
#include "kernel.h"

/**
 * Host function to execute RMSNorm.
 * 
 * Validates inputs, launches kernel on pre-allocated output tensor, and returns result.
 * 
 * @param hidden_states Input tensor [B, 7168] (BF16)
 * @param weight Weight tensor [7168] (BF16)
 * @param output Output tensor [B, 7168] (BF16) - pre-allocated
 * @return Output tensor [B, 7168] (BF16)
 */
torch::Tensor run(torch::Tensor hidden_states, torch::Tensor weight, torch::Tensor output) {
    // 1. Validate Device
    if (!hidden_states.is_cuda() || !weight.is_cuda() || !output.is_cuda()) {
        throw std::runtime_error("Input tensors must be on CUDA device");
    }

    // 2. Validate DType
    if (hidden_states.dtype() != at::kBFloat16 || weight.dtype() != at::kBFloat16 || output.dtype() != at::kBFloat16) {
        throw std::runtime_error("Input tensors must be of type BFloat16");
    }

    // 3. Validate Shapes
    int64_t hidden_size = hidden_states.size(1);
    if (hidden_size != HIDDEN_SIZE) {
        throw std::runtime_error("Hidden size must be 7168");
    }
    if (weight.size(0) != HIDDEN_SIZE) {
        throw std::runtime_error("Weight size must match hidden size (7168)");
    }
    if (output.size(0) != hidden_states.size(0) || output.size(1) != hidden_states.size(1)) {
        throw std::runtime_error("Output tensor shape must match input tensor shape");
    }

    // 4. Validate Contiguity
    if (!hidden_states.is_contiguous() || !weight.is_contiguous() || !output.is_contiguous()) {
        throw std::runtime_error("Input tensors must be contiguous");
    }

    int64_t batch_size = hidden_states.size(0);

    // 5. Launch Kernel
    launch_rmsnorm_kernel(hidden_states, weight, output, batch_size);

    // 6. Error Checking
    cudaError_t err = cudaGetLastError();
    if (err != cudaSuccess) {
        throw std::runtime_error(std::string("CUDA kernel error: ") + cudaGetErrorString(err));
    }

    return output;
}

// PyTorch Extension Binding
PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("run", &run, "Execute RMSNorm kernel optimized for A800");
}
